SYNTAX_CSS

# sidebar: show every top-level module on EVERY page (a persistent "Modules" menu), not only on the
# package landing. We override pdoc's nav_submodules block and list every rendered module.
cat > "$TMPL/module.html.jinja2" <<'JINJA'
{% extends "default/module.html.jinja2" %}
{% block module_list_link %}
    <a class="home-button" href="{{ "../" * module.modulename.count(".") }}microecs.html">Home</a>
{% endblock %}
{% block nav_submodules %}
    <h2>Modules</h2>
    <ul>
        {% for name in all_modules|sort if "." in name %}
            <li>{{ (name, "") | link(text=name) }}</li>
        {% endfor %}
    </ul>
{% endblock %}
JINJA

# --- render --------------------------------------------------------------------------------------
rm -rf "$OUT"
python - "$OUT" "$TMPL" <<'PY'
import sys, pathlib, microecs, pdoc, pdoc.render

out, tmpl = pathlib.Path(sys.argv[1]), pathlib.Path(sys.argv[2])
modules = sorted(p.stem for p in pathlib.Path("microecs").glob("*.py") if not p.stem.startswith("_"))

# Home page = README, with an autogenerated index of the module pages appended. We patch the
# IN-MEMORY module only (the tracked microecs/__init__.py is never touched): README becomes the
# package docstring, and __all__ is emptied so the landing stays README-only -- each class is
# documented on its own module page (linked from the sidebar), never inlined onto the home page.
links = "\n".join(f"- [`microecs.{m}`](microecs/{m}.html)" for m in modules)
microecs.__doc__ = pathlib.Path("README.md").read_text(encoding="utf-8") + f"\n\n## API reference\n\n{links}\n"
microecs.__all__ = []

pdoc.render.configure(template_directory=tmpl)
pdoc.pdoc("microecs", *(f"microecs.{m}" for m in modules), output_directory=out)
PY

echo "[docs] built $OUT/  ->  open file://$(cd "$OUT" && pwd)/index.html"
